return [{ json: { error: false, jobId: jobId, sql: sql, params: params, skills_weight: sk / 100, experience_weight: ex / 100, education_weight: ed / 100, criteria_text: criteriaText, criteria_items: criteriaItems } }];

const items = $input.all();
const first = items[0]?.json || {};
if (!first.job_id) {
  return [{ json: { error: true, message: 'Job not found, inactive, or no unevaluated candidates' } }];
}
const valNode = $('Eval - Validate Input').first().json;
const wSkills = Math.round((valNode.skills_weight || 0.4) * 100);
const wExp = Math.round((valNode.experience_weight || 0.35) * 100);
const wEdu = Math.round((valNode.education_weight || 0.25) * 100);
const criteriaText = valNode.criteria_text || '';
const criteriaItems = Array.isArray(valNode.criteria_items) ? valNode.criteria_items : [];
const jobDesc = criteriaText || first.job_description || '';
const today = new Date().toISOString().slice(0,10);
let itemsBlock = '';
let itemsKeys = '';
let itemsSchemaLine = '';
if (criteriaItems.length > 0) {
  const required = criteriaItems.filter(i => i.required);
  const sorted = [...criteriaItems].sort((a, b) => (b.importance || 5) - (a.importance || 5));
  const fmt = it => {
    const imp = Math.max(1, Math.min(10, parseInt(it.importance, 10) || 5));
    return `- [${it.required ? 'REQUIRED' : 'optional'}] (importance ${imp}/10) ${it.text}`;
  };
  itemsBlock = `\n\nITEMIZED CRITERIA (${criteriaItems.length} items, ${required.length} required, sorted by importance):\n${sorted.map(fmt).join('\n')}\n\nHOW TO USE THE IMPORTANCE NUMBER:\n- Importance 9-10 = CRITICAL. Failing these should heavily lower the relevant dimension scores (skills/experience/education) by 3+ points each.\n- Importance 6-8 = HIGH. Failing these should lower the relevant dimension scores by 1-2 points each.\n- Importance 3-5 = MEDIUM. Mild score impact.\n- Importance 1-2 = LOW / nice-to-have. Minimal score impact.\nA REQUIRED item with importance 9-10 that the candidate does NOT meet means the candidate is fundamentally unfit — overall score should reflect that.\nA REQUIRED item with low importance is a hard gate but small score impact when met.`;
  itemsKeys = ', "required_missing": ["req item not met", ...], "items_met": ["req item met", ...]';
  itemsSchemaLine = ' Include arrays "required_missing" and "items_met" referencing the exact REQUIRED item text.';
}
const results = [];
for (const item of items) {
  const cvText = (item.json.cv_text || '').substring(0, 9000);
  const prompt = `You are a professional HR evaluator. Analyze the following CV against the job requirements and provide a detailed evaluation.\n\nTODAY'S DATE: ${today}\nWhen evaluating any time-sensitive criterion (e.g. "graduating soon", "recent graduate", "X years of experience", "available immediately"), use TODAY'S DATE above as the reference. Do not assume a different current date.\n\nJOB TITLE: ${first.job_title}\nDEPARTMENT: ${first.department || 'N/A'}\nSENIORITY: ${first.seniority_level || 'N/A'}\nJOB DESCRIPTION / CRITERIA:\n${jobDesc.substring(0, 3000)}${itemsBlock}\n\nCRITICAL SCORING RULES:\n- Score the candidate ONLY against the JOB DESCRIPTION / CRITERIA above. Those criteria define what matters for THIS role — do not invent or substitute your own criteria.\n- Relevance is mandatory: skills or experience that are impressive but NOT relevant to this role's criteria must NOT raise the scores.\n- If the candidate's field/background does not match what this role requires, skills_score and experience_score MUST be low (typically 0-3), no matter how strong their unrelated background is.\n- education_score reflects fit with the role's stated educational requirements, not prestige alone.\n- Reserve high scores (8-10) only for candidates who clearly satisfy the stated criteria.\n\nSCORING WEIGHTS: Skills ${wSkills}%, Experience ${wExp}%, Education ${wEdu}%\n\nCANDIDATE CV:\n${cvText}\n\nEvaluate this candidate thoroughly. Consider their skills match, years and relevance of experience, education credentials, and overall fit.${itemsSchemaLine}\n\nYou MUST respond with ONLY a valid JSON object in this exact format (no other text before or after):\n{\"skills_score\": <number 0-10>, \"experience_score\": <number 0-10>, \"education_score\": <number 0-10>, \"strengths\": [\"strength1\", \"strength2\", \"strength3\"], \"weaknesses\": [\"weakness1\", \"weakness2\"], \"reasoning\": \"Brief explanation of your evaluation\"${itemsKeys}}`;
  results.push({ json: {
    error: false,
    candidate_id: item.json.candidate_id,
    candidate_name: item.json.candidate_name,
    job_opening_id: item.json.job_id,
    prompt: prompt,
    requestBody: JSON.stringify({ systemInstruction: { parts: [{ text: 'You are an expert HR analyst. Score candidates objectively based on the provided criteria. Respond ONLY with valid JSON matching the requested schema—no preamble, no markdown.' }] }, contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.1, maxOutputTokens: 4096, responseMimeType: 'application/json' } }),
    wSkills: wSkills / 100,
    wExp: wExp / 100,
    wEdu: wEdu / 100,
    has_items: criteriaItems.length > 0
  }});
}
return results;

const items = $input.all();
const promptItems = $('Eval - Prepare Prompts').all();
const results = [];
function extractJson(text) {
  if (!text) return null;
  text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  try { return JSON.parse(text); } catch(_) {}
  const start = text.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  for (let i = start; i < text.length; i++) {
    if (text[i] === '{') depth++;
    else if (text[i] === '}') {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.slice(start, i + 1)); } catch(_) { return null; }
      }
    }
  }
  return null;
}
function clampScore(v) {
  const n = typeof v === 'number' ? v : parseFloat(v);
  return isNaN(n) ? null : Math.min(10, Math.max(0, Math.round(n * 10) / 10));
}
function toStr(v) { return Array.isArray(v) ? v.join('; ') : (v || ''); }
for (let i = 0; i < items.length; i++) {
  const raw = items[i].json;
  const meta = promptItems[i]?.json || {};
  const wSkills = meta.wSkills || 0.4;
  const wExp = meta.wExp || 0.35;
  const wEdu = meta.wEdu || 0.25;
  let aiText = ((raw.candidates?.[0]?.content?.parts?.[0]?.text || '') || '').trim();
  // Gemini doesn't have a separate thinking field
  const parsed = extractJson(aiText);
  let skillsScore = parsed ? clampScore(parsed.skills_score) : null;
  let expScore = parsed ? clampScore(parsed.experience_score) : null;
  let eduScore = parsed ? clampScore(parsed.education_score) : null;
  let strengths, weaknesses, reasoning, parseError = false;
  if (skillsScore !== null && expScore !== null && eduScore !== null) {
    strengths = toStr(parsed.strengths);
    weaknesses = toStr(parsed.weaknesses);
    reasoning = parsed.reasoning || 'AI evaluation by Gemini';
    if (meta.has_items) {
      const missing = toStr(parsed.required_missing);
      const met = toStr(parsed.items_met);
      if (missing) reasoning += '\n\nRequired items NOT met: ' + missing;
      if (met) reasoning += '\n\nRequired items met: ' + met;
    }
  } else {
    skillsScore = 0; expScore = 0; eduScore = 0;
    strengths = '';
    weaknesses = '';
    reasoning = 'AI evaluation failed to produce structured scores. Please re-run the evaluation.';
    parseError = true;
  }
  const overall = Math.round((skillsScore * wSkills + expScore * wExp + eduScore * wEdu) * 10) / 10;
  results.push({ json: {
    error: false,
    parse_error: parseError,
    candidate_id: meta.candidate_id,
    candidate_name: meta.candidate_name,
    job_opening_id: meta.job_opening_id,
    overall_score: overall,
    skills_score: skillsScore,
    experience_score: expScore,
    education_score: eduScore,
    reasoning: reasoning,
    strengths: strengths,
    weaknesses: weaknesses,
    sql: 'INSERT INTO evaluations (candidate_id, job_opening_id, overall_score, skills_score, experience_score, education_score, reasoning, strengths, weaknesses) VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9) RETURNING *',
    params: [meta.candidate_id, meta.job_opening_id, overall, skillsScore, expScore, eduScore, reasoning, strengths, weaknesses]
  }});
}
return results;

const scores = $('Eval - Score Candidates').all();
const candidates = scores.map(s => ({
  candidate_id: s.json.candidate_id,
