return [{ json: { error: false, candidate: { id: row.candidate_id, name: row.candidate_name, email: row.email }, job: { id: row.job_opening_id, title: row.job_title, department: row.department }, includeHr: ctx.includeHr, includeTechnical: ctx.includeTechnical, includeSalary: ctx.includeSalary, numQuestions: ctx.numQuestions, requestBody: JSON.stringify({ systemInstruction: { parts: [{ text: 'You are a senior recruiter. Generate professional, conversational interview questions. Respond ONLY with valid JSON matching the requested schema—no preamble, no markdown.' }] }, contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.3, maxOutputTokens: 4000, responseMimeType: 'application/json' } }) } }];

