if (ctx.includeTechnical) allowed.add('technical');
if (ctx.includeSalary) allowed.add('salary');
const fallbackCategory = ctx.includeHr ? 'hr' : (ctx.includeTechnical ? 'technical' : 'salary');
// Map
// common variants to the canonical names so we don't silently drop valid questions and end up
// returning fewer than the user asked for.
const ALIASES = {
  hr: 'hr', behavioral: 'hr', behavioural: 'hr', behavior: 'hr', behaviour: 'hr',
  soft: 'hr', 'soft skills': 'hr', cultural: 'hr', 'cultural fit': 'hr', motivation: 'hr', personality: 'hr',
  technical: 'technical', tech: 'technical', skills: 'technical', skill: 'technical', engineering: 'technical', coding: 'technical',
  salary: 'salary', compensation: 'salary', pay: 'salary', 'expected salary': 'salary', comp: 'salary'
};
const cleaned = parsed.questions
  .filter(q => q && q.question)
  .map(q => {
    const rawCat = String(q.category || '').toLowerCase().trim();
    const aliased = ALIASES[rawCat] || rawCat;
    const cat = allowed.has(aliased) ? aliased : fallbackCategory;
    return { category: cat, question: String(q.question).trim(), hints: String(q.hints || '').trim() };
  })
  .slice(0, ctx.numQuestions);
return [{ json: { success: true, candidate: ctx.candidate, job: ctx.job, questions: cleaned, _source: raw._source || 'gemini' } }];

const orig = $('Eval - Prepare Prompts').item.json;
const geminiReq = JSON.parse(orig.requestBody || '{}');
const sysText = geminiReq.systemInstruction?.parts?.[0]?.text || '';
const userText = geminiReq.contents?.[0]?.parts?.[0]?.text || '';
const expectJson = geminiReq.generationConfig?.responseMimeType === 'application/json';
const temp = geminiReq.generationConfig?.temperature ?? 0.3;
return [{ json: { ...orig, requestBody: JSON.stringify({ model: 'qwen3:4b', prompt: (sysText ? sysText + '\n\n' : '') + userText, stream: false, ...(expectJson ? { format: 'json' } : {}), options: { temperature: temp, num_predict: 4000 } }) } }];

const r = $json;
// qwen3 puts response in thinking field when in thinking mode; try all locations
const text = r.response || r.thinking || r.message?.content || '';
return [{ json: { candidates: [{ content: { parts: [{ text }] } }], _source: r.error ? 'ollama_failed' : 'ollama', _model: r.model } }];

